import omni.usd
from pxr import Usd, UsdPhysics, PhysxSchema, Sdf
import omni.graph.core as og

stage = omni.usd.get_context().get_stage()

# 1) Find the real articulation root under /World/NovaCarter
art_root = None
for prim in Usd.PrimRange(stage.GetPrimAtPath("/World/NovaCarter")):
    if prim.HasAPI(UsdPhysics.ArticulationRootAPI) or prim.HasAPI(PhysxSchema.PhysxArticulationAPI):
        art_root = prim.GetPath().pathString
        print(f"Articulation root found: {art_root}")
        break

if art_root is None:
    # Fallback: apply to chassis_link
    chassis = stage.GetPrimAtPath("/World/NovaCarter/chassis_link")
    if chassis.IsValid():
        UsdPhysics.ArticulationRootAPI.Apply(chassis)
        PhysxSchema.PhysxArticulationAPI.Apply(chassis)
        art_root = "/World/NovaCarter/chassis_link"
        print(f"Applied ArticulationRootAPI to {art_root}")
    else:
        raise RuntimeError("No chassis_link found")

# 2) Patch ArticulationController nodes in both graphs
for graph_path in ["/World/Graphs/CarterControl", "/World/Graphs/CarterTeleop"]:
    gprim = stage.GetPrimAtPath(graph_path)
    if not gprim.IsValid():
        print(f"  (skip) {graph_path} not found")
        continue
    for prim in Usd.PrimRange(gprim):
        tname = prim.GetTypeName()
        if "ArticulationController" in str(tname) or prim.GetName().lower().startswith("articulationcontroller"):
            # Set robotPath input
            rp_attr = prim.GetAttribute("inputs:robotPath")
            if rp_attr and rp_attr.IsValid():
                rp_attr.Set(art_root)
                print(f"  {prim.GetPath()}.inputs:robotPath = {art_root}")
            # Also try targetPrim relationship (some versions use it)
            tp_rel = prim.GetRelationship("inputs:targetPrim")
            if tp_rel and tp_rel.IsValid():
                tp_rel.SetTargets([Sdf.Path(art_root)])
                print(f"  {prim.GetPath()}.inputs:targetPrim -> {art_root}")

# 3) Also fix PublishJointState target
for graph_path in ["/World/Graphs/CarterControl"]:
    gprim = stage.GetPrimAtPath(graph_path)
    if not gprim.IsValid():
        continue
    for prim in Usd.PrimRange(gprim):
        if "PublishJointState" in prim.GetName() or "ROS2PublishJointState" in str(prim.GetTypeName()):
            tp_rel = prim.GetRelationship("inputs:targetPrim")
            if tp_rel and tp_rel.IsValid():
                tp_rel.SetTargets([Sdf.Path(art_root)])
                print(f"  {prim.GetPath()}.inputs:targetPrim -> {art_root}")

print("\n[OK] Graphs retargeted. Stop and restart Play for changes to take effect.")

